INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('362f7e09f9075abd', 'VA', '["state"]', 'election_dates', 'Are the Governor or State Legislature on the 2026 ballot?', '["Is there a governor''s race in 2026?","State senate election 2026","When do we vote for the House of Delegates?"]', 'No. Virginia is distinctive in that it elects its Governor, Lieutenant Governor, Attorney General, State Senate, and House of Delegates in odd-numbered years. Therefore, these state-level offices will not be on the 2026 ballot.', 'https://law.lis.virginia.gov/constitution/article4/section3/', 'Constitution of Virginia, Article IV, Section 3 & Article V, Section 1', '2026-05-10', 'static', 'statute_citation', 'Applies to candidate and voter awareness for the 2026 cycle.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('b4c1c5b823fdb5e8', 'VA', '["federal"]', 'election_dates', 'What federal offices are on the 2026 ballot in Virginia?', '["Are there congressional races in 2026?","Is Mark Warner up for reelection?","Federal offices 2026"]', 'All 11 of Virginia''s U.S. House of Representatives seats and one U.S. Senate seat (the Class 2 seat currently held by Mark Warner) will be on the 2026 general election ballot.', 'https://www.elections.virginia.gov/casting-a-ballot/calendars-schedules/', 'Virginia Department of Elections – Calendars & Schedules', '2026-05-10', 'per_cycle', 'official_source_direct', 'Applies to candidates for federal office.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('e3023095bd72d8fa', 'VA', '["federal","county","municipal"]', 'voter_interaction', 'Does Virginia have closed primaries?', '["Do I have to register as a Republican to vote in the primary?","Party registration rules","Open primary state"]', 'No. Virginia is an open primary state and does not register voters by political party. Any registered voter may vote in either the Republican or Democratic primary, but they may only vote in one party''s primary per election day.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter5/section24.2-530/', 'Va. Code § 24.2-530', '2026-05-10', 'static', 'statute_citation', 'Applies to all voters participating in primary elections.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('d52ddc27b5cf0645', 'VA', '["federal","county","municipal"]', 'ballot_access', 'Can the party choose to hold a convention or firehouse primary instead of a state-run primary?', '["Party-run nominations","What is a firehouse primary?","Can the GOP cancel the primary and hold a convention?"]', 'Yes. In Virginia, the political party committee has the legal authority to determine its own method of nomination. They can choose a state-run primary, a party-run assembled caucus (convention), an unassembled caucus (firehouse primary), or a mass meeting.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter5/section24.2-509/', 'Va. Code § 24.2-509', '2026-05-10', 'static', 'statute_citation', 'Applies to political parties and candidates seeking party nominations.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('930592ba6f2d2900', 'VA', '["federal","county","municipal","special_district"]', 'finance_ethics', 'What is the maximum individual contribution limit for a campaign?', '["How much can one person donate?","Maximum campaign contribution cap","Individual donor limits"]', 'Virginia has NO campaign contribution limits. An individual may contribute an unlimited amount of money to state and local candidate campaigns.', 'https://www.elections.virginia.gov/candidatepac-info/campaign-finance/', 'Virginia Department of Elections – Campaign Finance', '2026-05-10', 'static', 'official_source_direct', 'Applies to individuals donating to Virginia campaigns.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('9856bba56f8fa45f', 'VA', '["federal","county","municipal","special_district"]', 'finance_ethics', 'Can a corporation or labor union donate directly to my campaign?', '["Are corporate contributions legal?","Can a business write a campaign check?","LLC donation rules"]', 'Yes. Unlike the federal government and many other states, Virginia law permits corporations, LLCs, and labor unions to make direct, unlimited financial contributions to state and local political campaigns.', 'https://www.elections.virginia.gov/candidatepac-info/campaign-finance/', 'Virginia Department of Elections – Campaign Finance', '2026-05-10', 'static', 'official_source_direct', 'Applies to candidate campaigns accepting business funds.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('939f75a6e9e1b021', 'VA', '["federal","county","municipal","special_district"]', 'finance_ethics', 'How much can a PAC donate to my campaign?', '["PAC contribution limits","Political committee donation caps","Do PACs have giving limits?"]', 'There are no contribution limits for Political Action Committees (PACs) donating to state and local campaigns in Virginia. They may contribute unlimited amounts.', 'https://www.elections.virginia.gov/candidatepac-info/campaign-finance/', 'Virginia Department of Elections – Campaign Finance', '2026-05-10', 'static', 'official_source_direct', 'Applies to PACs donating to state and local campaigns.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('d86ed6ea0a1cdff4', 'VA', '["county","municipal","special_district"]', 'recall_rules', 'Can an elected official be recalled from office by voters in Virginia?', '["How do we recall a mayor?","Recall election procedures","Removing an official early"]', 'Virginia does not have a traditional popular recall election mechanism on the ballot. Instead, it uses a court-driven ''Removal of Public Officers'' process where citizens petition a circuit court to hold a trial to remove the official.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter2/section24.2-233/', 'Va. Code § 24.2-233', '2026-05-10', 'static', 'statute_citation', 'Applies to voters inquiring about recalling elected officials.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('32ec967d8e75369d', 'VA', '["county","municipal","special_district"]', 'recall_rules', 'How many signatures are required for a removal petition against an official?', '["Recall signature threshold","Math for removal petitions","How many people need to sign to trigger a trial?"]', 'A removal petition requires valid signatures from registered voters equal to at least 10% of the total number of votes cast at the last election specifically for the office that the targeted officer holds (not 10% of all registered voters).', 'https://law.lis.virginia.gov/vacode/title24.2/chapter2/section24.2-233/', 'Va. Code § 24.2-233', '2026-05-10', 'static', 'statute_citation', 'Applies to organizers of a removal petition.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('602a74083fa9db5f', 'VA', '["county","municipal","special_district"]', 'recall_rules', 'What are the legal grounds to remove an elected official via petition?', '["Why can an official be removed?","Recall justification","Reasons required for a removal trial"]', 'The petition must state with reasonable accuracy that the official committed malfeasance, misuse of office, incompetence, neglect of duty, or was convicted of certain crimes or intoxicated in public.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter2/section24.2-233/', 'Va. Code § 24.2-233', '2026-05-10', 'static', 'statute_citation', 'Applies to individuals initiating a removal process.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('6c0c4546dfe18559', 'VA', '["judicial"]', 'election_dates', 'When do voters elect judges in Virginia?', '["Judicial election dates","Are judges on the ballot?","How are judges chosen?"]', 'They do not. In Virginia, Supreme Court Justices, Court of Appeals Judges, Circuit Court Judges, and District Court Judges are not elected by popular public ballot; they are elected directly by a majority vote of the General Assembly.', 'https://law.lis.virginia.gov/constitution/article6/section7/', 'Constitution of Virginia, Article VI, Section 7', '2026-05-10', 'static', 'statute_citation', 'Applies to the selection of Virginia state judges.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('154a9293e821561a', 'VA', '["county"]', 'election_dates', 'Which county-level constitutional officers are elected by voters?', '["What local offices are on the ballot?","Are sheriffs elected?","Constitutional officer elections"]', 'Voters directly elect five local constitutional officers: the Sheriff, Commonwealth''s Attorney, Clerk of the Circuit Court, Commissioner of the Revenue, and Treasurer.', 'https://law.lis.virginia.gov/constitution/article7/section4/', 'Constitution of Virginia, Article VII, Section 4', '2026-05-10', 'static', 'statute_citation', 'Applies to candidates for local constitutional offices.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('b0f3ec68288c1377', 'VA', '["federal","county","municipal"]', 'voter_interaction', 'How far from the polling place entrance must campaign volunteers stay?', '["Electioneering distance rules","Where can we hold signs at the polls?","Buffer zone restrictions"]', 'Virginia enforces a strictly defined 40-foot Prohibited Area extending from any entrance of the polling place, within which campaigning, handing out flyers, and loitering are illegal.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter6/section24.2-604/', 'Va. Code § 24.2-604(A)', '2026-05-10', 'static', 'statute_citation', 'Applies to all campaign volunteers and electioneers.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('93525b5dbbf52cc3', 'VA', '["federal","county","municipal"]', 'election_dates', 'How long is the early voting period?', '["When does early voting start?","In-person absentee voting dates","Duration of early voting window"]', 'Virginia has one of the longest early voting periods in the country. No-excuse in-person early voting begins 45 days before the election and ends at 5:00 p.m. on the Saturday immediately preceding the election.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter7/section24.2-701.1/', 'Va. Code § 24.2-701.1(A)', '2026-05-10', 'static', 'statute_citation', 'Applies to all elections offering early voting.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('972f7abc5b5fe47f', 'VA', '["federal","county","municipal"]', 'election_dates', 'When is the 2026 Primary Election in Virginia?', '["VA primary date 2026","When do voters vote in the primary?","June primary date"]', 'The primary election in Virginia is statutorily set for the third Tuesday in June. For the 2026 cycle, this is Tuesday, June 16, 2026.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter5/section24.2-515/', 'Va. Code § 24.2-515', '2026-05-10', 'per_cycle', 'statute_citation', 'Applies to all voters and candidates on the primary ballot.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('945714092202e3cf', 'VA', '["federal","county","municipal","special_district"]', 'election_dates', 'When is the 2026 General Election in Virginia?', '["Election day 2026","What date is the November election?","Fall general election date"]', 'The 2026 General Election is scheduled for Tuesday, November 3, 2026.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter1/section24.2-101/', 'Va. Code § 24.2-101', '2026-05-10', 'per_cycle', 'statute_citation', 'Applies to all voters and candidates.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('3221823c3fde4c62', 'VA', '["federal","county","municipal"]', 'voter_interaction', 'Is a photo ID required to vote in person in Virginia?', '["Voter ID rules","Voting without a driver''s license","Acceptable forms of identification at the polls"]', 'While photo IDs are accepted, Virginia law also accepts non-photo forms of ID (e.g., current utility bill or bank statement). If a voter has no ID, they may sign an ID Confirmation Statement under penalty of perjury and cast a REGULAR ballot. If they refuse to sign, they must cast a provisional ballot.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter6/section24.2-643/', 'Va. Code § 24.2-643(B)', '2026-05-10', 'static', 'statute_citation', 'Applies to all in-person voters.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('d00f479053eca5e0', 'VA', '["federal","county","municipal"]', 'ballot_access', 'When is the deadline to file a Declaration of Candidacy for the June 2026 primary?', '["When do I file for office?","Primary qualifying dates","Deadline to submit candidacy paperwork"]', 'For a primary held on the third Tuesday in June, a candidate must file their Declaration of Candidacy no later than 5:00 p.m. on the first Thursday in April. For the 2026 cycle, this is April 2, 2026.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter5/section24.2-522/', 'Va. Code § 24.2-522(A)', '2026-05-10', 'per_cycle', 'statute_citation', 'Applies to candidates seeking state-run primary ballot access.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('7e1c7c61bdce0633', 'VA', '["federal","county","municipal"]', 'ballot_access', 'Can a candidate run as an independent in the general election if they lose the party primary?', '["Sore loser law","Running as an independent after losing","Can a primary loser run in November?"]', 'No. Under Virginia''s ''Sore Loser'' law, a candidate who is defeated in a primary election cannot have their name printed on the ballot for the subsequent general election for the same office.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter5/section24.2-520/', 'Va. Code § 24.2-520', '2026-05-10', 'static', 'statute_citation', 'Applies to candidates defeated in a partisan primary.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('e83bd68d80d7584c', 'VA', '["federal","county","municipal"]', 'ballot_access', 'What is the procedure for running as a write-in candidate?', '["How do I register as a write-in?","Do write-in votes automatically count?","Pre-registration for write-ins"]', 'Unlike many states, Virginia does not require write-in candidates to file a declaration of intent or pre-register for general elections; any written-in name is legally counted. However, write-in votes are strictly prohibited in primary elections.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter6/section24.2-644/', 'Va. Code § 24.2-644(C) & § 24.2-529', '2026-05-10', 'static', 'statute_citation', 'Applies to all individuals seeking write-in status.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('98c49852229c6030', 'VA', '["county","municipal"]', 'finance_ethics', 'When must I file my Statement of Economic Interests (SOEI)?', '["SOEI deadline","When do I file financial disclosures?","Ethics paperwork timing"]', 'A candidate must file their SOEI by the deadline for filing their written declaration of candidacy. Failure to file on time disqualifies the candidate from having their name printed on the ballot.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter5/section24.2-502/', 'Va. Code § 24.2-502', '2026-05-10', 'static', 'statute_citation', 'Applies to candidates required to file the SOEI.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('7900c9a9e187b88d', 'VA', '["federal","county","municipal"]', 'candidate_eligibility', 'Can an individual with a felony conviction vote or run for office in Virginia?', '["Felony voting rights","Can felons vote after prison?","Restoration of rights in VA"]', 'A felony conviction results in the loss of voting and candidacy rights. These rights are NOT automatically restored upon sentence completion; an individual must submit an application to the Governor of Virginia, who restores rights on a manual, case-by-case basis at their sole discretion.', 'https://law.lis.virginia.gov/constitution/article2/section1/', 'Constitution of Virginia, Article II, Section 1', '2026-05-10', 'volatile', 'statute_citation', 'Applies to Virginia residents with past felony convictions.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('1158b9bb20ea1594', 'VA', '["federal","county","municipal"]', 'voter_interaction', 'When is the deadline to request a mail-in absentee ballot?', '["Last day to ask for a mail ballot","Cutoff to request absentee","Mail ballot request deadline"]', 'An application requesting an absentee ballot by mail must be received by the local general registrar no later than 5:00 p.m. on the eleventh day prior to the election.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter7/section24.2-701/', 'Va. Code § 24.2-701(B)(1)', '2026-05-10', 'static', 'statute_citation', 'Applies to voters requiring absentee-by-mail ballots.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('ecd64fdb9a571e0c', 'VA', '["federal","county","municipal"]', 'election_dates', 'What is the standard voter registration deadline?', '["When do the voter registration books close?","Registration cutoff date","Last day to register to vote"]', 'The standard deadline to register to vote is 22 days before the election. However, Virginia allows Same-Day Registration during early voting and on Election Day, but same-day registrants MUST vote a provisional ballot.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter4/section24.2-416/', 'Va. Code § 24.2-416(A) & § 24.2-416.1', '2026-05-10', 'static', 'statute_citation', 'Applies to all unregistered eligible voters.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('93b43ae682345151', 'VA', '["federal","county","municipal"]', 'voter_interaction', 'How does my campaign appoint a poll watcher?', '["Designating poll observers","Can I put poll watchers inside the voting location?","Rules for Authorized Representatives"]', 'In Virginia, poll watchers are called ''Authorized Representatives.'' They are appointed by the local party chair (or by the candidate if running independent). Each party/independent candidate may have up to three representatives in the polling place at a time.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter6/section24.2-604.4/', 'Va. Code § 24.2-604.4', '2026-05-10', 'static', 'statute_citation', 'Applies to political parties and independent candidates organizing poll watchers.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('8f8f486624d2385c', 'VA', '["federal"]', 'ballot_access', 'What is the primary filing fee to run for U.S. Senate or U.S. House?', '["How much to run for Congress?","Congressional filing fee","Qualifying fee for federal office"]', 'Virginia uses a statutory percentage formula for primary filing fees. Candidates must pay 2% of the minimum annual salary for the office. Based on the $174,000 federal salary, the fee for U.S. House or U.S. Senate is $3,480.00. (Independent candidates do not pay a filing fee).', 'https://law.lis.virginia.gov/vacode/title24.2/chapter5/section24.2-523/', 'Va. Code § 24.2-523', '2026-05-10', 'per_cycle', 'statute_citation', 'Applies to candidates seeking a party nomination for U.S. Congress.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('a22ec29394695f57', 'VA', '["county"]', 'ballot_access', 'What is the primary filing fee for local constitutional officers like Sheriff or Treasurer?', '["Filing fee for county office","How much does it cost to run for local office?","Cost for constitutional officers"]', 'The primary filing fee is 2% of the minimum annual salary for the specific office in that locality. By law, the fee can never be less than $100.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter5/section24.2-523/', 'Va. Code § 24.2-523', '2026-05-10', 'per_cycle', 'statute_citation', 'Applies to candidates seeking a party nomination for local constitutional offices.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('4ab9fb48af347cb6', 'VA', '["federal"]', 'ballot_access', 'How many petition signatures does a candidate need to run for U.S. Senate or Statewide office?', '["Signature requirement for Senate","Petition threshold for statewide office","How many signatures for Governor?"]', 'A candidate for U.S. Senate or statewide office must submit 10,000 signatures from qualified voters, which must include at least 400 signatures from each of the state''s 11 congressional districts.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter5/section24.2-506/', 'Va. Code § 24.2-506', '2026-05-10', 'static', 'statute_citation', 'Applies to both primary and independent candidates for statewide office.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('00630b699753ef3c', 'VA', '["federal"]', 'ballot_access', 'How many petition signatures are required to run for U.S. House of Representatives?', '["Signature requirement for Congress","How many signatures for US House?","Petition threshold for congressional district"]', 'A candidate for the U.S. House of Representatives must submit 1,000 signatures from qualified voters registered within that specific congressional district.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter5/section24.2-506/', 'Va. Code § 24.2-506', '2026-05-10', 'static', 'statute_citation', 'Applies to both primary and independent candidates for the U.S. House.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('971bccac3126a91a', 'VA', '["state","county","municipal"]', 'ballot_access', 'How many petition signatures are required for the state legislature or local constitutional officers?', '["Signature requirement for local office","How many signatures for Sheriff?","Petition threshold for county board"]', 'For State Senate, 250 signatures are required. For House of Delegates and local constitutional officers, 125 signatures are required. However, for local offices in counties/cities with a population under 100,000, only 50 signatures are required.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter5/section24.2-506/', 'Va. Code § 24.2-506', '2026-05-10', 'static', 'statute_citation', 'Applies to both primary and independent candidates for state legislative and local office.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('26f8006d9f370409', 'VA', '["federal","county","municipal"]', 'ballot_access', 'What official forms must I file to qualify as a candidate?', '["Notice of candidacy requirements","What forms get me on the ballot?","SBE-501 requirements"]', 'A candidate must file a Certificate of Candidate Qualification (Form SBE-501), a Declaration of Candidacy (SBE-505/520), the required petition signatures, and a Statement of Economic Interests (SOEI).', 'https://www.elections.virginia.gov/candidatepac-info/becoming-a-candidate/', 'Virginia Department of Elections – Becoming a Candidate', '2026-05-10', 'static', 'official_source_direct', 'Applies to all candidates qualifying for the ballot.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('72dd31297895f682', 'VA', '["federal","state","county","municipal"]', 'finance_ethics', 'When do I have to officially appoint a campaign treasurer?', '["Do I need a treasurer before I raise money?","Filing the Statement of Organization","When does a campaign legally begin?"]', 'A candidate must designate a campaign treasurer and establish a campaign depository BEFORE accepting any contributions or spending any money. The Statement of Organization (SBE-501.1) must be filed within 10 days of meeting the candidate definition.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter9.3/section24.2-947.1/', 'Va. Code § 24.2-947.1(A)', '2026-05-10', 'static', 'statute_citation', 'Applies to all candidates.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('08d7eaf0bc91bf79', 'VA', '["federal","state","county","municipal"]', 'finance_ethics', 'Does my campaign bank account have to be at a Virginia bank?', '["Campaign depository rules","Can I use an out-of-state bank?","Where can I open my campaign account?"]', 'Yes. All campaign funds must be deposited into a primary campaign depository located in a financial institution that is authorized to do business in the Commonwealth of Virginia.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter9.3/section24.2-947.1/', 'Va. Code § 24.2-947.1(C)', '2026-05-10', 'static', 'statute_citation', 'Applies to all campaign treasurers.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('c5ad5c3c70e55b75', 'VA', '["state","county","municipal"]', 'finance_ethics', 'What is the standard campaign finance reporting schedule in an election year?', '["How often do I file finance reports?","When are disclosure reports due?","Election year reporting schedule"]', 'In an election year, reports are due April 15, June 1, July 15, September 15, and October 15. Additionally, candidates must file an 8-day pre-primary report, an 8-day pre-general report, a 30-day post-general report, and a year-end report on January 15.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter9.3/section24.2-947.6/', 'Va. Code § 24.2-947.6', '2026-05-10', 'static', 'statute_citation', 'Applies to candidates active on the ballot in the current year.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('e2277ff793888b0b', 'VA', '["state","county","municipal"]', 'finance_ethics', 'When is the specific pre-election finance report due before the November election?', '["8-day pre-election report","When is the last finance report due before voting?","Reporting schedule right before the election"]', 'An eighth pre-election report must be filed no later than the eighth day before the November election, and it must be complete through the thirteenth day before the election.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter9.3/section24.2-947.6/', 'Va. Code § 24.2-947.6(A)(8)', '2026-05-10', 'static', 'statute_citation', 'Applies to all candidates active on the November ballot.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('283f6fa819bc1cbd', 'VA', '["state","county","municipal"]', 'finance_ethics', 'Can I use campaign funds to pay my personal mortgage or buy a personal car?', '["Personal use of campaign funds","The Virginia campaign finance loophole","Impermissible uses of campaign cash"]', 'Historically, Virginia has no statutory prohibition against the personal use of campaign funds (the ''loophole''). However, this is a highly volatile area with intense legislative pushes in 2024-2025 to ban personal use. Candidates must verify if a ban has formally taken effect for the 2026 cycle.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter9.3/section24.2-938/', 'Va. Code § 24.2-938', '2026-05-10', 'volatile', 'statute_citation', 'Applies to all state and local candidates and officeholders.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('d8179ea05f77ffa5', 'VA', '["state","county","municipal"]', 'finance_ethics', 'What is the penalty for filing a campaign finance report late?', '["How much are late fees for ethics reports?","Fines for missing a deadline","Department of Elections penalties"]', 'The Department of Elections assesses a civil penalty of $100 for a late report. If the report is not filed within 60 days of the due date, the penalty increases to $500, and further delays can lead to referral to the Commonwealth''s Attorney.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter9.3/section24.2-953.1/', 'Va. Code § 24.2-953.1', '2026-05-10', 'per_cycle', 'statute_citation', 'Applies to all candidates failing to file disclosure reports on time.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('055a90ed4774c9b7', 'VA', '["state","county","municipal"]', 'finance_ethics', 'How do I report a personal loan made to my own campaign?', '["Lending money to myself","Do personal loans count as contributions?","Funding my own campaign"]', 'A loan to the campaign, whether from a bank, a third party, or the candidate''s personal funds, must be disclosed on Schedule E (Loans) of the campaign finance report until it is fully repaid or forgiven.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter9.3/section24.2-947.4/', 'Va. Code § 24.2-947.4(E)', '2026-05-10', 'static', 'statute_citation', 'Applies to all campaigns acquiring debt.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('8e37324911ed27fd', 'VA', '["state","county","municipal"]', 'finance_ethics', 'When does an ''Independent Expenditure'' require reporting to the state?', '["IE reporting threshold","When do independent groups have to disclose?","Threshold for third-party reporting"]', 'Any person or PAC making independent expenditures totaling $1,000 or more in an election cycle must file an independent expenditure report within 24 hours if the expenditure is made within the 11 days immediately preceding the election.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter9.3/section24.2-945.2/', 'Va. Code § 24.2-945.2', '2026-05-10', 'per_cycle', 'statute_citation', 'Applies to individuals and groups making political expenditures.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('facad9a1a8e8c7f0', 'VA', '["state","county","municipal"]', 'finance_ethics', 'What is the penalty if a single large contribution is reported late right before the election?', '["Late fee for large pre-election donations","Penalty for missing the 24-hour report","Fines for late big checks"]', 'Any single contribution of $1,000 or more for statewide candidates, or $500 or more for non-statewide candidates, received between the 11th day preceding the election and Election Day must be reported within 24 hours.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter9.3/section24.2-947.9/', 'Va. Code § 24.2-947.9', '2026-05-10', 'per_cycle', 'statute_citation', 'Applies to campaigns receiving large late contributions.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('d50bd4b47d9df3ed', 'VA', '["state","county","municipal"]', 'finance_ethics', 'How do I value an in-kind contribution of goods or services?', '["In-kind valuation","How much is a donated venue worth?","Reporting free services"]', 'In-kind contributions must be reported at the fair market value of the good or service at the time it was provided. Because Virginia has no contribution limits, the value does not cap the donor, but it must be fully transparently reported.', 'https://www.elections.virginia.gov/candidatepac-info/campaign-finance/', 'Virginia Department of Elections – Campaign Finance', '2026-05-10', 'static', 'official_source_direct', 'Applies to all campaigns accepting non-monetary donations.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('30f76ddd20deee4f', 'VA', '["state","county","municipal"]', 'finance_ethics', 'What is a ''bundled'' contribution and how is it reported?', '["Bundling donations","Reporting checks gathered by a fundraiser","Do bundlers count against limits?"]', 'A bundled contribution is when a third party collects multiple checks from individuals and delivers them together. The campaign must report the actual original contributors. Since Virginia has no contribution limits, bundling is a transparency issue, not a limit-evasion issue.', 'https://www.elections.virginia.gov/candidatepac-info/campaign-finance/', 'Virginia Department of Elections – Campaign Finance', '2026-05-10', 'static', 'official_source_direct', 'Applies to campaigns utilizing fundraisers who gather checks.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('7ceed16b0f77f89f', 'VA', '["state","county","municipal"]', 'finance_ethics', 'Who oversees candidate financial disclosures and ethics rules in Virginia?', '["Who handles ethics complaints?","Where do I file the SOEI?","Ethics regulatory body"]', 'The Virginia Conflict of Interest and Ethics Advisory Council is the state body responsible for administering the Statement of Economic Interests (SOEI) and providing formal advisory opinions on ethics laws.', 'http://ethics.dls.virginia.gov/', 'Virginia Conflict of Interest and Ethics Advisory Council', '2026-05-10', 'static', 'official_source_direct', 'Applies to all candidates and public officers.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('c7eb357ee1833ffe', 'VA', '["state"]', 'finance_ethics', 'Do state legislators have to file additional financial disclosures beyond the standard candidate SOEI?', '["Legislative financial disclosures","Do state reps file different ethics forms?","General Assembly SOEI"]', 'Yes. Members of the General Assembly must file a distinct General Assembly Statement of Economic Interests, which includes broader disclosure requirements regarding lobbying relationships and legislative conflicts, due annually.', 'http://ethics.dls.virginia.gov/', 'Virginia Conflict of Interest and Ethics Advisory Council', '2026-05-10', 'static', 'official_source_direct', 'Applies exclusively to members and candidates of the General Assembly.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('1b206b85778821ff', 'VA', '["state","county","municipal"]', 'finance_ethics', 'Can I use campaign funds to pay for legal defense?', '["Paying lawyers with donor money","Are legal fees a campaign expense?","Defending against ethics complaints"]', 'Yes. Because Virginia places virtually no restrictions on the permissible uses of campaign funds, a candidate may use campaign contributions to pay for legal fees and defense costs.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter9.3/section24.2-938/', 'Va. Code § 24.2-938 (Context)', '2026-05-10', 'static', 'statute_citation', 'Applies to candidates facing legal challenges.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('eb72f36fb67ae118', 'VA', '["federal","state","county","municipal"]', 'finance_ethics', 'What official form is used to register my campaign committee?', '["Statement of Organization form","What paperwork opens my campaign?","How do I register my committee?"]', 'A candidate must file a Statement of Organization (Form SBE-501.1) within 10 days of receiving their first contribution or spending their first dollar.', 'https://www.elections.virginia.gov/candidatepac-info/becoming-a-candidate/', 'Virginia Department of Elections – Becoming a Candidate', '2026-05-10', 'static', 'official_source_direct', 'Applies to all newly formed campaign committees.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('962b80b15bf1eb3a', 'VA', '["state","county","municipal"]', 'finance_ethics', 'When does a PAC or Political Party Committee have to register with the state?', '["PAC registration threshold","When do independent groups have to disclose?","Threshold for third-party reporting"]', 'A political action committee (PAC) must file a Statement of Organization within 10 days of anticipating that it will receive contributions or make expenditures in excess of $200 in a calendar year.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter9.3/section24.2-949.2/', 'Va. Code § 24.2-949.2', '2026-05-10', 'per_cycle', 'statute_citation', 'Applies to PACs operating in Virginia.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('b1a7451c6dfb520f', 'VA', '["state","county","municipal"]', 'finance_ethics', 'Can I hold a joint fundraising event with another candidate?', '["Joint fundraising rules","Sharing campaign event costs","Splitting money with another candidate"]', 'Yes. Candidates may hold joint fundraisers, but because Virginia has no contribution limits, the primary concern is accurate reporting. Costs and contributions must be appropriately allocated and reported by the respective campaign treasurers.', 'https://www.elections.virginia.gov/candidatepac-info/campaign-finance/', 'Virginia Department of Elections – Campaign Finance', '2026-05-10', 'static', 'official_source_direct', 'Applies to campaigns pooling resources for fundraising.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('c4f85b6fa2bfb22e', 'VA', '["federal","state","county","municipal"]', 'ballot_access', 'Do I need to submit my petition signatures to the state or the local registrar?', '["Where do I turn in my signatures?","Who verifies petitions?","Filing location for candidates"]', 'Signatures for statewide and federal offices must be submitted to the State Board of Elections. Signatures for local and General Assembly offices are submitted directly to the general registrar of the locality where the candidate resides.', 'https://www.elections.virginia.gov/candidatepac-info/becoming-a-candidate/', 'Virginia Department of Elections – Becoming a Candidate', '2026-05-10', 'static', 'official_source_direct', 'Applies to all candidates utilizing the petition method.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('9b58d112df7f3a29', 'VA', '["state","county","municipal"]', 'finance_ethics', 'Do I have to file my campaign finance reports electronically?', '["Electronic filing requirements","Can I submit paper finance reports?","How to submit the disclosure form"]', 'Statewide and General Assembly candidates are required to file campaign finance reports electronically via the COMET system. Local candidates may file on paper with their local registrar, unless they have raised or spent $10,000 or more, which triggers mandatory electronic filing.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter9.3/section24.2-947.5/', 'Va. Code § 24.2-947.5', '2026-05-10', 'per_cycle', 'statute_citation', 'Applies to all candidates filing finance reports.', 'batch_2026-05-10T18-20-15_virginia_full_v1')
INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('fbfbee3feffc2375', 'VA', '["federal","county","municipal"]', 'voter_interaction', 'What are the basic voter eligibility requirements in Virginia?', '["Who can register to vote?","Voting age and citizenship","Can out of state college students vote?"]', 'To vote in Virginia, an individual must be a resident of Virginia, a U.S. citizen, and 18 years old by the date of the next general election.', 'https://law.lis.virginia.gov/constitution/article2/section1/', 'Constitution of Virginia, Article II, Section 1', '2026-05-10', 'static', 'statute_citation', 'Applies to all individuals seeking to register to vote.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('b6a5fdcfbeaebdb7', 'VA', '["federal","state","county","municipal"]', 'candidate_eligibility', 'Do I have to be a registered voter to run for office?', '["Qualified voter definition","Can I run if I''m not registered to vote?","Voter registration requirement for candidates"]', 'Yes. The Virginia Constitution explicitly requires that anyone holding any office of trust or profit be a ''qualified voter'' of the Commonwealth, meaning they must be legally registered and eligible to vote.', 'https://law.lis.virginia.gov/constitution/article2/section5/', 'Constitution of Virginia, Article II, Section 5', '2026-05-10', 'static', 'statute_citation', 'Applies to all candidates for elected office.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('6f978d4e250dd8ed', 'VA', '["federal"]', 'residency', 'What are the residency requirements to run for U.S. House in Virginia?', '["Federal residency rules","Can I run for Congress if I don''t live in the district?","US House eligibility"]', 'A candidate for the U.S. House must be at least 25 years old, a citizen for 7 years, and an ''inhabitant'' of Virginia when elected. The U.S. Constitution does not require the candidate to live within the specific boundaries of the congressional district.', 'https://www.elections.virginia.gov/candidatepac-info/becoming-a-candidate/', 'Virginia Department of Elections – Candidate Qualifications', '2026-05-10', 'static', 'official_source_direct', 'Applies to candidates for the United States House of Representatives.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('9d75016fd60d27fe', 'VA', '["state"]', 'residency', 'What are the residency and age requirements to run for Governor or Attorney General?', '["How old to run for governor?","Residency rules for statewide office","Qualifications for Attorney General"]', 'Candidates for Governor, Lieutenant Governor, and Attorney General must be at least 30 years old, a U.S. citizen, and have been a resident and registered voter of Virginia for at least five years preceding the election.', 'https://law.lis.virginia.gov/constitution/article5/section3/', 'Constitution of Virginia, Article V, Section 3', '2026-05-10', 'static', 'statute_citation', 'Applies to candidates for statewide executive offices.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('ff2a38fdaedf6ba6', 'VA', '["county","municipal"]', 'residency', 'Do I have to live in my precinct for a certain amount of time before I can vote there?', '["30-day residency rule","When do I have to move by to vote?","Precinct residency rules"]', 'No. Virginia eliminated its former 30-day precinct residency requirement. Currently, a person may register and vote from their new residence immediately upon establishing it as their permanent domicile.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter4/section24.2-417/', 'Va. Code § 24.2-417 (Context)', '2026-05-10', 'static', 'statute_citation', 'Applies to voters who have recently relocated.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('062ab3f74c204653', 'VA', '["county","municipal"]', 'ballot_access', 'When is the qualifying deadline for a local candidate if the party holds a mass meeting instead of a primary?', '["Local caucus deadlines","When do I file if there is no primary?","Party-run nomination deadlines"]', 'If a political party nominates a candidate via a method other than a primary (like a caucus or mass meeting), the party chair must certify the nominee''s name to the State Board of Elections within five days of the nomination being made, or by the primary date, whichever is earlier.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter5/section24.2-511/', 'Va. Code § 24.2-511', '2026-05-10', 'static', 'statute_citation', 'Applies to local candidates nominated by party caucus/convention.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('8d3baf5ec9704f3f', 'VA', '["federal","state","county","municipal"]', 'finance_ethics', 'What is the difference between the State Board of Elections and the Department of Elections?', '["Who do I complain to?","SBE vs ELECT","Virginia election administration structure"]', 'The State Board of Elections (SBE) is a bipartisan, policy-making body that ensures uniformity and approves regulations. The Department of Elections (ELECT) is the executive agency that administers the laws, handles candidate filings, and runs the actual election machinery.', 'https://www.elections.virginia.gov/board/', 'Virginia Department of Elections – State Board', '2026-05-10', 'static', 'official_source_direct', 'Applies to understanding Virginia''s election bureaucracy.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('d50d7ea9f125013e', 'VA', '["state","county","municipal"]', 'finance_ethics', 'At what dollar amount do I have to itemize a donor on my campaign finance report?', '["When do I ask for an employer?","Occupation reporting threshold","Do I need job info for small donations?"]', 'A campaign must itemize (report the name, address, occupation, and employer) any contributor whose total aggregate contributions to the campaign exceed $100 for the election cycle.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter9.3/section24.2-947.4/', 'Va. Code § 24.2-947.4(D)', '2026-05-10', 'per_cycle', 'statute_citation', 'Applies to all campaigns tracking donor data.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('7d29155815b65844', 'VA', '["state","county","municipal"]', 'finance_ethics', 'Are political party committees subject to contribution limits when donating to my campaign?', '["Party committee contribution limits","Can the GOP give me unlimited money?","State party funding rules"]', 'No. Because Virginia has no contribution limits for ANY entity, political party committees may contribute unlimited amounts to their nominees without restriction.', 'https://www.elections.virginia.gov/candidatepac-info/campaign-finance/', 'Virginia Department of Elections – Campaign Finance', '2026-05-10', 'static', 'official_source_direct', 'Applies to candidates receiving formal political party support.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('253ffdd27cc99f9b', 'VA', '["state","county","municipal"]', 'finance_ethics', 'Can I use campaign funds to buy a car for my campaign?', '["The Cabbage Patch issue","Buying vehicles with donor money","Permissive use of funds for equipment"]', 'Yes. Because Virginia currently places minimal restrictions on the use of campaign funds, a candidate can purchase a vehicle or other equipment. However, if the asset is converted to personal use post-election, it triggers intense political and IRS scrutiny.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter9.3/section24.2-938/', 'Va. Code § 24.2-938', '2026-05-10', 'volatile', 'statute_citation', 'Applies to campaigns purchasing high-value physical assets.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('8af5e44aa5b4981c', 'VA', '["state"]', 'finance_ethics', 'If I am a registered lobbyist, what are the restrictions on interacting with campaigns?', '["Can lobbyists donate to candidates?","Lobbying rules and campaign finance","Restrictions on lobbyist activity"]', 'Lobbyists in Virginia may donate to campaigns, but they are strictly prohibited from contributing to or soliciting contributions for members of the General Assembly or statewide officials during any regular legislative session.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter9.5/section24.2-954/', 'Va. Code § 24.2-954', '2026-05-10', 'static', 'statute_citation', 'Applies to registered lobbyists engaging with campaigns.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('4685d04f653943d4', 'VA', '["state","county","municipal"]', 'finance_ethics', 'How long must my campaign treasurer keep our financial records?', '["Record retention rules","How long do I save receipts?","Keeping finance reports post-election"]', 'Campaign treasurers must maintain detailed accounts, records, and receipts for a period of three (3) years from the date the final campaign finance report is filed.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter9.3/section24.2-947.3/', 'Va. Code § 24.2-947.3', '2026-05-10', 'static', 'statute_citation', 'Applies to all campaign treasurers and candidates.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('3898dca1bcd529a8', 'VA', '["federal","county","municipal"]', 'voter_interaction', 'Under what circumstances is a voter issued a provisional ballot?', '["Why do people vote provisionally?","What if a voter isn''t on the rolls?","Voting without an ID"]', 'A provisional ballot is issued if a voter''s name does not appear on the pollbook, if they refuse to sign the ID Confirmation Statement when lacking ID, or if they register using Same-Day Registration on Election Day.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter6/section24.2-653/', 'Va. Code § 24.2-653', '2026-05-10', 'static', 'statute_citation', 'Applies to voters facing eligibility issues at the polls.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('aa0bd1cfeebc9697', 'VA', '["federal","county","municipal"]', 'voter_interaction', 'Can a campaign volunteer help a voter mark their ballot inside the polling place?', '["Voter assistance rules","Who can help someone vote in the booth?","Can I help my mom vote?"]', 'Yes. A voter who requires assistance due to physical disability or inability to read may request assistance from any person of their choice, EXCEPT an agent of their employer or their labor union.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter6/section24.2-649/', 'Va. Code § 24.2-649(B)', '2026-05-10', 'static', 'statute_citation', 'Applies to all voters needing assistance and volunteers providing it.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('7f754818cc3216cc', 'VA', '["federal","county","municipal"]', 'voter_interaction', 'When is the specific deadline to return a mail-in absentee ballot?', '["Absentee return deadline","How late can an absentee ballot arrive?","Does postmark matter for mail ballots?"]', 'Absentee ballots must be physically received by the local registrar by 7:00 p.m. on Election Day. Alternatively, if postmarked by Election Day, they will be counted if received by noon on the third day following the election. (Note: The postmark grace period faces frequent legislative challenges).', 'https://law.lis.virginia.gov/vacode/title24.2/chapter7/section24.2-709/', 'Va. Code § 24.2-709(A)', '2026-05-10', 'volatile', 'statute_citation', 'Applies to domestic civilian voters returning mail ballots.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('696e518d42c7e5a9', 'VA', '["federal","county","municipal"]', 'voter_interaction', 'Can a voter drop off their absentee ballot instead of mailing it?', '["Drop box locations","Can I hand deliver my ballot?","Where can I return an absentee ballot?"]', 'Yes. Voters may return their absentee ballot to a designated drop-off location situated at the office of the general registrar, or at any satellite early voting location operating in the county/city during early voting hours.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter7/section24.2-707.1/', 'Va. Code § 24.2-707.1', '2026-05-10', 'static', 'statute_citation', 'Applies to voters returning mail ballots in person.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('740755231e35b025', 'VA', '["federal","county","municipal"]', 'ballot_access', 'How is the order of candidate names determined on the ballot in Virginia?', '["Ballot order rules","Do incumbents get listed first?","Is the ballot order randomized?"]', 'For general elections, the political party whose candidate won the most votes in the last gubernatorial election gets the first spot on the ballot, followed by other recognized parties, and then independents. Primary ballot order is determined by a random drawing by the State Board.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter6/section24.2-613/', 'Va. Code § 24.2-613', '2026-05-10', 'static', 'statute_citation', 'Applies to all candidates appearing on the ballot.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('c8c187e33763c356', 'VA', '["federal","county","municipal"]', 'ballot_access', 'What happens if I want to withdraw my candidacy after I qualify?', '["How do I quit the race?","Removing my name from the ballot","Withdrawal procedures and refunds"]', 'A candidate may withdraw their candidacy by filing a signed, notarized notice of withdrawal (Form ELECT-612.12) with the Department of Elections. If withdrawn before ballots are printed, the name is removed; if after, notices are posted at polls.', 'https://www.elections.virginia.gov/candidatepac-info/becoming-a-candidate/', 'Virginia Department of Elections – Candidate Withdrawal', '2026-05-10', 'static', 'official_source_direct', 'Applies to candidates wishing to officially terminate their campaign.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('e7b20314b3bf7fb4', 'VA', '["federal"]', 'redistricting', 'What congressional map is being used for the 2026 elections?', '["Did the Supreme Court strike down the Virginia map?","Current redistricting map","Status of CD lines"]', 'The congressional maps drawn by special masters appointed by the Supreme Court of Virginia in late 2021 remain legally active and unchallenged for the 2026 cycle.', 'https://www.elections.virginia.gov/casting-a-ballot/redistricting/', 'Virginia Department of Elections – Redistricting', '2026-05-10', 'static', 'official_source_direct', 'Applies to all candidates and voters in Virginia Congressional districts.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('4d8c5321002ae91b', 'VA', '["federal","county","municipal"]', 'ballot_access', 'How and when can I legally challenge an opponent''s eligibility to run for office?', '["Candidacy challenge procedure","Proving my opponent doesn''t live in the district","Filing a protest against a candidate"]', 'A challenge to a candidate''s qualifications or petition signatures must be filed in writing with the Department of Elections no later than 10 days after the filing deadline for the office.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter5/section24.2-506/', 'Va. Code § 24.2-506 (Context)', '2026-05-10', 'static', 'statute_citation', 'Applies to individuals initiating eligibility disputes against candidates.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('8774557b4a6a08dd', 'VA', '["federal","county","municipal"]', 'voter_interaction', 'Are campaign signs allowed to be placed on state highway rights-of-way?', '["Can I put signs in the median?","Highway campaign sign rules","Does the state take down political signs?"]', 'No. Virginia law explicitly bans the placement of political signs in the right-of-way of any state highway. The Virginia Department of Transportation (VDOT) is authorized to immediately remove them as hazards.', 'https://law.lis.virginia.gov/vacode/title33.2/chapter12/section33.2-1224/', 'Va. Code § 33.2-1224', '2026-05-10', 'static', 'statute_citation', 'Applies to all campaigns placing signage.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('ade053676aaf980e', 'VA', '["federal","county","municipal"]', 'finance_ethics', 'What are the disclaimer rules for campaign robocalls?', '["Robocall rules","Voice call political advertising","Do auto-dialers need to say who paid for it?"]', 'Automated political calls (robocalls) must clearly state the identity of the person or organization paying for the call at the beginning of the message, and must provide a return telephone number.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter9.5/section24.2-955.1/', 'Va. Code § 24.2-955.1', '2026-05-10', 'static', 'statute_citation', 'Applies to all campaigns conducting phone outreach.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('02c6475e69df85a0', 'VA', '["federal","county","municipal"]', 'finance_ethics', 'Do SMS text messages sent to voters require a political disclaimer?', '["Text messaging campaign rules","Do campaign texts need disclaimers?","Mass texting disclosure"]', 'Yes. Campaign text messages fall under Virginia''s print and electronic media advertising disclosure statutes. Mass texts must include a ''Paid for by'' sponsorship legend, either directly in the text or via a clear link.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter9.5/section24.2-956/', 'Va. Code § 24.2-956', '2026-05-10', 'static', 'statute_citation', 'Applies to all campaigns using mass SMS.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('e589ae2887c0ba2f', 'VA', '["federal","county","municipal"]', 'finance_ethics', 'Does my campaign website or digital ad require a ''Paid for by'' disclaimer?', '["Digital advertising disclaimers","Do Facebook ads need disclosures?","Website paid-for rules"]', 'Yes. Political advertising published in print, broadcast on TV/radio, or distributed via digital advertising platforms (like Facebook, Google, or campaign websites) must include a clear disclosure stating who paid for the communication.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter9.5/section24.2-956/', 'Va. Code § 24.2-956', '2026-05-10', 'static', 'statute_citation', 'Applies to all campaigns running digital advertisements.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('b39056a424700452', 'VA', '["judicial"]', 'election_dates', 'How are General District Court Judges selected in Virginia?', '["Are lower court judges elected?","General District Court elections","Selection process for district judges"]', 'Like the higher courts, General District Court Judges are not elected by popular ballot in Virginia. They are chosen by a majority vote of the General Assembly for a term of six years.', 'https://law.lis.virginia.gov/constitution/article6/section7/', 'Constitution of Virginia, Article VI, Section 7', '2026-05-10', 'static', 'statute_citation', 'Applies to the selection of Virginia lower court judges.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('582a380b45391943', 'VA', '["special_district"]', 'election_dates', 'Are Soil and Water Conservation District Directors elected by the public?', '["Special district elections","Are soil and water boards elected?","Who votes for the conservation district?"]', 'Yes. Distinct from standard judicial positions, Soil and Water Conservation District Directors are popularly elected nonpartisan offices. They appear on the general election ballot.', 'https://law.lis.virginia.gov/vacode/title10.1/chapter5/section10.1-523/', 'Va. Code § 10.1-523', '2026-05-10', 'static', 'statute_citation', 'Applies to candidates for soil and water conservation districts.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('ded3c450bb7bdca3', 'VA', '["federal","county","municipal"]', 'finance_ethics', 'If my campaign coordinates with a PAC on an advertisement, is it still an ''Independent Expenditure''?', '["PAC coordination rules","What if a super PAC talks to me?","Coordinated spending definition"]', 'No. If an expenditure is coordinated with, made with the cooperation of, or made at the request of a candidate, it is legally considered an ''in-kind'' contribution to the campaign. Because VA has no contribution limits, this simply requires accurate reporting by the campaign.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter9.3/section24.2-945.1/', 'Va. Code § 24.2-945.1', '2026-05-10', 'static', 'statute_citation', 'Applies to campaigns interacting with outside PACs.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('3374aa7f6189c84c', 'VA', '["state","county","municipal"]', 'finance_ethics', 'What must I do with my surplus campaign funds after the election?', '["Disposing of leftover money","Can I keep my campaign cash?","Final campaign account closure"]', 'Surplus funds may be returned pro-rata to contributors, donated to a tax-exempt charitable organization, given to a recognized political party, transferred to a future campaign, or (controversially) utilized for personal use under current law.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter9.3/section24.2-938/', 'Va. Code § 24.2-938', '2026-05-10', 'volatile', 'statute_citation', 'Applies to candidates concluding an election cycle.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('3b026635befb253f', 'VA', '["state","county","municipal"]', 'finance_ethics', 'Can I transfer leftover funds from my city council race to a new campaign for Mayor?', '["Transferring funds between offices","Rolling over money to a new race","Using local money for a different run"]', 'Yes. Virginia law allows you to retain campaign funds and transfer them for use in a future campaign for the same office or a completely different state/local office.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter9.3/section24.2-938/', 'Va. Code § 24.2-938', '2026-05-10', 'static', 'statute_citation', 'Applies to candidates shifting offices between cycles.', 'batch_2026-05-10T18-20-15_virginia_full_v1'),
  ('47958108502524b3', 'VA', '["state","county","municipal"]', 'finance_ethics', 'How do I officially close my campaign account after the election?', '["Ending my campaign reporting obligations","Filing the termination report","How to stop filing ethics reports"]', 'To end reporting obligations, a candidate must file a Final Report indicating a zero balance, no outstanding debts, and confirming that all surplus funds have been properly disposed of or transferred.', 'https://law.lis.virginia.gov/vacode/title24.2/chapter9.3/section24.2-948.4/', 'Va. Code § 24.2-948.4', '2026-05-10', 'static', 'statute_citation', 'Applies to all candidates wishing to terminate their campaign treasurer appointment.', 'batch_2026-05-10T18-20-15_virginia_full_v1')
